import { useState } from 'react';
import { useNavigate, Link } from 'react-router-dom';
import API from '../../services/axios';

const CATEGORIES = ['Concert', 'Conference', 'Workshop', 'Sports', 'Exhibition', 'Festival', 'Comedy', 'Theatre', 'Other'];

function CreateEvent() {
  const navigate = useNavigate();
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [success, setSuccess] = useState('');
  const [form, setForm] = useState({ name: '', description: '', date: '', time: '', venue: '', category: 'Concert', totalSeats: '', price: '', image: '' });

  const handleChange = (e) => setForm({ ...form, [e.target.name]: e.target.value });

  const handleSubmit = async (e) => {
    e.preventDefault(); setError(''); setLoading(true);
    try {
      await API.post('/events', { ...form, totalSeats: parseInt(form.totalSeats), price: parseFloat(form.price) });
      setSuccess('Event created successfully! 🎉');
      setTimeout(() => navigate('/admin/manage-events'), 1500);
    } catch (err) {
      setError(err.response?.data?.message || 'Failed to create event');
    } finally { setLoading(false); }
  };

  const inp = { width: '100%', padding: '11px 14px', background: 'white', border: '1.5px solid #f0ddd7', borderRadius: '11px', color: '#2d1f1f', fontSize: '0.88rem', outline: 'none', boxSizing: 'border-box', fontFamily: "'DM Sans', sans-serif" };

  return (
    <div style={{ padding: '2rem', background: '#fdf6f3', minHeight: '100vh', fontFamily: "'DM Sans', sans-serif" }}>
      <div style={{ marginBottom: '1.5rem' }}>
        <Link to="/admin" style={{ color: '#c9a99a', textDecoration: 'none', fontSize: '0.84rem', fontWeight: '600' }}>← Back to Dashboard</Link>
        <h1 style={{ fontSize: '1.6rem', fontWeight: '700', color: '#2d1f1f', marginTop: '8px', fontFamily: "'Cormorant Garamond', serif" }}>Create New Event</h1>
      </div>

      <div style={{ background: 'white', borderRadius: '20px', padding: '2rem', maxWidth: '700px', boxShadow: '0 4px 20px rgba(201,169,154,0.1)', border: '1px solid #f5e8e3' }}>
        {error && <div style={{ background: '#fdeee9', border: '1px solid #f0c4b8', color: '#a05040', padding: '12px 16px', borderRadius: '12px', marginBottom: '1.5rem', fontSize: '0.84rem' }}>⚠️ {error}</div>}
        {success && <div style={{ background: '#edf5f0', border: '1px solid #b8d8c8', color: '#3a7a5a', padding: '12px 16px', borderRadius: '12px', marginBottom: '1.5rem', fontSize: '0.84rem' }}>✅ {success}</div>}

        <form onSubmit={handleSubmit}>
          <div style={{ display: 'grid', gap: '1.1rem' }}>

            <div>
              <label style={{ display: 'block', color: '#6b5a55', fontSize: '0.76rem', fontWeight: '700', marginBottom: '7px' }}>EVENT NAME *</label>
              <input name="name" value={form.name} onChange={handleChange} required style={inp} placeholder="e.g. Summer Music Festival"
                onFocus={e => e.target.style.borderColor = '#c9a99a'} onBlur={e => e.target.style.borderColor = '#f0ddd7'} />
            </div>

            <div>
              <label style={{ display: 'block', color: '#6b5a55', fontSize: '0.76rem', fontWeight: '700', marginBottom: '7px' }}>DESCRIPTION *</label>
              <textarea name="description" value={form.description} onChange={handleChange} required rows={3}
                style={{ ...inp, resize: 'vertical' }} placeholder="Describe your event..."
                onFocus={e => e.target.style.borderColor = '#c9a99a'} onBlur={e => e.target.style.borderColor = '#f0ddd7'} />
            </div>

            <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '1rem' }}>
              <div>
                <label style={{ display: 'block', color: '#6b5a55', fontSize: '0.76rem', fontWeight: '700', marginBottom: '7px' }}>DATE *</label>
                <input type="date" name="date" value={form.date} onChange={handleChange} required style={inp}
                  onFocus={e => e.target.style.borderColor = '#c9a99a'} onBlur={e => e.target.style.borderColor = '#f0ddd7'} />
              </div>
              <div>
                <label style={{ display: 'block', color: '#6b5a55', fontSize: '0.76rem', fontWeight: '700', marginBottom: '7px' }}>TIME *</label>
                <input type="time" name="time" value={form.time} onChange={handleChange} required style={inp}
                  onFocus={e => e.target.style.borderColor = '#c9a99a'} onBlur={e => e.target.style.borderColor = '#f0ddd7'} />
              </div>
            </div>

            <div>
              <label style={{ display: 'block', color: '#6b5a55', fontSize: '0.76rem', fontWeight: '700', marginBottom: '7px' }}>VENUE *</label>
              <input name="venue" value={form.venue} onChange={handleChange} required style={inp} placeholder="e.g. Mumbai Arena"
                onFocus={e => e.target.style.borderColor = '#c9a99a'} onBlur={e => e.target.style.borderColor = '#f0ddd7'} />
            </div>

            <div>
              <label style={{ display: 'block', color: '#6b5a55', fontSize: '0.76rem', fontWeight: '700', marginBottom: '7px' }}>CATEGORY *</label>
              <select name="category" value={form.category} onChange={handleChange} style={inp}
                onFocus={e => e.target.style.borderColor = '#c9a99a'} onBlur={e => e.target.style.borderColor = '#f0ddd7'}>
                {CATEGORIES.map(c => <option key={c} value={c}>{c}</option>)}
              </select>
            </div>

            <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '1rem' }}>
              <div>
                <label style={{ display: 'block', color: '#6b5a55', fontSize: '0.76rem', fontWeight: '700', marginBottom: '7px' }}>TOTAL SEATS *</label>
                <input type="number" name="totalSeats" value={form.totalSeats} onChange={handleChange} required min="1" style={inp} placeholder="500"
                  onFocus={e => e.target.style.borderColor = '#c9a99a'} onBlur={e => e.target.style.borderColor = '#f0ddd7'} />
              </div>
              <div>
                <label style={{ display: 'block', color: '#6b5a55', fontSize: '0.76rem', fontWeight: '700', marginBottom: '7px' }}>PRICE (₹) *</label>
                <input type="number" name="price" value={form.price} onChange={handleChange} required min="0" style={inp} placeholder="999"
                  onFocus={e => e.target.style.borderColor = '#c9a99a'} onBlur={e => e.target.style.borderColor = '#f0ddd7'} />
              </div>
            </div>

            <div>
              <label style={{ display: 'block', color: '#6b5a55', fontSize: '0.76rem', fontWeight: '700', marginBottom: '7px' }}>IMAGE URL (optional)</label>
              <input name="image" value={form.image} onChange={handleChange} style={inp} placeholder="https://example.com/image.jpg"
                onFocus={e => e.target.style.borderColor = '#c9a99a'} onBlur={e => e.target.style.borderColor = '#f0ddd7'} />
            </div>

            <div style={{ display: 'flex', gap: '1rem', marginTop: '0.5rem' }}>
              <button type="submit" disabled={loading} style={{ flex: 2, background: 'linear-gradient(135deg, #c9a99a, #b8887a)', color: 'white', border: 'none', padding: '13px', borderRadius: '12px', cursor: 'pointer', fontWeight: '700', fontSize: '0.9rem', fontFamily: "'DM Sans', sans-serif", opacity: loading ? 0.7 : 1, boxShadow: '0 6px 20px rgba(201,169,154,0.35)' }}>
                {loading ? '⏳ Creating...' : '✅ Create Event'}
              </button>
              <Link to="/admin" style={{ flex: 1, background: '#f5e8e3', color: '#a08880', padding: '13px', borderRadius: '12px', textDecoration: 'none', fontWeight: '600', textAlign: 'center', fontSize: '0.9rem' }}>
                Cancel
              </Link>
            </div>
          </div>
        </form>
      </div>
    </div>
  );
}
export default CreateEvent;
